import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly escape user input to prevent XSS vulnerability
        String escapedUserInput = Encode.forHtml(userInput);

        // Write the escaped user input to the output file
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html><body>");
        out.println("<p>User Input: " + escapedUserInput + "</p>");
        out.println("</body></html>");

        out.close();
    }
}

